var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"도착했습니다, 누님!","JPN":"着きました、姉貴！","ENG":"We've arrived, ma'am!","TWN":"到了，大姊頭！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"여기부터는 침식파의 영향권이라 저희는 못 들어갈 것 같습니다.","JPN":"ここからは侵食波の影響圏内になるので、俺たちは入れそうにないです。","ENG":"The Corruption rays are too strong that I don't think we can go any further from here.","TWN":"從這裡開始就是侵蝕波的影響範圍了，我們的話就進不去了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그렇군요. 수고했어요.","JPN":"そうですか。ご苦労様でした。","ENG":"Okay. Good work.","TWN":"原來如此，辛苦了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"사례금입니다. 기름값이라고 생각하고 받으세요.","JPN":"これは謝礼金です。ガソリン代だと思って受け取ってください。","ENG":"Here's your pay. Think of it as gas money.","TWN":"這是酬金。就當是油錢，收下吧。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"가, 감사합니다! 살펴가십시오!","JPN":"あ、ありがとうございます！　どうかお気をつけて！","ENG":"Th-thank you! Good luck!","TWN":"非，非常感謝！請慢走！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"어제의 적이 오늘의 협력자라…….","JPN":"昨日の敵が今日の協力者、か……","ENG":"Yesterday's enemy is today's ally, huh...?","TWN":"昨日的敵人成為了今天的合作夥伴……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"크, 이런 게 바로 용병의 프로페셔널 아니겠어?","JPN":"くぅ～これぞ傭兵のプロフェッショナルだな！","ENG":"Damn, guess that's what it means to be a pro mercenary, eh?","TWN":"哼，這才是雇傭兵的專業精神，不是嗎？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"그런데 저 여자는 대체 저렇게 위험한 곳에 왜 가려고 하는 걸까요?","JPN":"でもあの女、なんであんな危険な場所に行くんですかね？","ENG":"But why does she even want to go to such a dangerous place?","TWN":"但那個女人為什麼要去那樣危險的地方呢？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"쯧쯧, 이래서 네가 아직 애송이라는 거야.","JPN":"チッチッ。これだからお前はまだガキなんだよ。","ENG":"Tsk, tsk. That's why you're still a punk.","TWN":"嘖嘖，所以說你還是個不入流。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"그야 복수심을 품은 외로운 거미가 스캐빈저에게 독니를 꽂으러 가는 거지.","JPN":"決まってるだろ。復讐心に燃える孤独なクモが、スカベンジャーに再び毒牙をぶっ刺しに行くんだ。","ENG":"It's because the vengeful lonely spider is going to sink her venomous fangs into the Scavengers.","TWN":"懷著復仇之心的獨狼蜘蛛，正準備將她的毒牙刺入清道夫體內。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"네에?","JPN":"ええっ……？","ENG":"What?","TWN":"啊啊？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"어쩌면 우리는…….","JPN":"もしかしたら俺たちは……","ENG":"Maybe...","TWN":"哼哼，也許我們……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"이곳에서 곧 엄청난 복수극을 마주하게 될지도 몰라.","JPN":"この後、とんでもない復讐劇を目撃することになるかもしれないな。","ENG":"We might soon face a tremendous revenge here.","TWN":"可能很快就會在這裡迎來一場盛大的復仇戲碼。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……코러스.","JPN":"……コーラス。","ENG":"...Chorus.","TWN":"……Chorus。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제프티 사가 파산 절차를 밟은 뒤, 연구 자료를 빼돌리면서 관련 문서를 본 적이 있어.","JPN":"ジェフティ社が破産手続きを終えた後、研究資料を盗んで関係書類に目を通したことがある。","ENG":"After Jehuty went through the bankruptcy proceedings, I saw related documents while stealing their research material.","TWN":"在傑夫堤進行破產程式時，我曾經偷看過他們的研究資料和相關檔。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제프티를 뒤에서 조종하던 그림자들이 막대한 자본을 들여 인양해 낸 로스트 쉽…….","JPN":"ジェフティを裏で操っていたシャドウたちが莫大な資本を投入して引き揚げたロストシップ……","ENG":"The Shadows that controlled Jehuty behind the scenes spent immense capital to salvage the Lost Ship...","TWN":"在幕後操縱傑夫堤的暗影們花費鉅資打撈上來的失落艦船……"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"원래 이건 엘리시움의 세계에서 사용되던 함선이야.","JPN":"もともとこれはエリシウムの世界で使われた艦船。","ENG":"This was originally a ship used in Elysium's world.","TWN":"這原本是愛樂世界中使用的艦船。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 당연하게도 이면세계에 오랫동안 방치된 함선을 그대로 쓸 수는 없었어.","JPN":"しかし当然ながら、長い間裏世界に放置されていた艦船をそのまま使えるはずはなかった。","ENG":"But of course, it can't be used as is because it has been abandoned in the Counterside for all this time.","TWN":"理所當然地，長期被遺棄在異界的艦船無法直接使用。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"가장 핵심이 되는 메인 프레임을 제외하면, 개장 및 보수 작업에서 제프티의 기술력이 대거 사용되었지.","JPN":"要となるメインフレーム以外は改装や補修作業が行われ、ジェフティの技術力が多く使われた。","ENG":"Excluding the essential main frame, Jehuty's technology was used extensively to remodel and repair it.","TWN":"除了最核心的主框架外，改造和維修工程中使用了大量傑夫堤的技術。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그로 인해 발생하는 필연적인 문제들…….","JPN":"それによって発生する必然的な問題……","ENG":"And the inevitable problems that arise as a result are...","TWN":"由此產生的必然問題……"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"부품의 호환성, 표준화되지 않은 OS, 양산화 설비를 갖추기 위한 재해석 등등…….","JPN":"部品の互換性、標準化されていないOS、量産化設備を備えるための再解析……","ENG":"compatibility of parts, non-standardized OS, a reinterpretation of the ship for mass production, and so on...","TWN":"部件的相容性、未標準化的作業系統、為量產設備進行的重新解釋等等……"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이런저런 사정으로, 제프티 사의 손을 거친 코러스는 꽤나 결이 다른 함선이 되었어.","JPN":"結果的に、ジェフティ社の手に渡ったコーラスは、最初とはかなり違う艦船になった。","ENG":"For one reason or another, Chorus has become an entirely different ship after Jehuty got its hands on it.","TWN":"由於種種原因，經由傑夫堤公司之手，Chorus變成了一艘截然不同的艦船。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"오히려 상당부분은 관리국 표준 함선과 비슷한 구조를 띠게 되었지.","JPN":"どちらかと言えば、管理局の標準艦船に近い構造だった。","ENG":"The majority of it now resembles a similar structure to that of the Administration ships.","TWN":"反而在很大程度上呈現出與管理局標準艦船相似的結構。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};